Insert into SPONSORED_AD (AD_NO,BUSINESS_NAME,BUSINESS_TYPE,AD_TITLE,AD_TEXT,AREA,IMAGE_URL,CTA_TEXT,LINK_URL,VIEW_COUNT,CLICK_COUNT,AD_STATUS,DISPLAY_ORDER,CDATE,ADDRESS,PHONE,OPEN_HOURS,MAIN_MENU,PRICE_INFO,PARKING_INFO,MAP_URL,INSTAGRAM_URL) values (1,'북촌 달빛찻집','CAFE','북촌 골목 산책 후 들르기 좋은 감성 찻집','한옥 골목을 걷다가 조용히 쉬어가기 좋은 찻집이에요. 전통차와 디저트를 함께 즐길 수 있어요.','서울 종로구','https://images.unsplash.com/photo-1544787219-7f47ccb76574?auto=format&fit=crop&w=1400&q=80','가게 보기','https://map.naver.com',325,36,'ACTIVE',1,to_date('26/06/04','RR/MM/DD'),'서울특별시 종로구 북촌로 00길 12','02-1234-5678','매일 10:00 - 21:00 / 라스트오더 20:30','대표 메뉴, 로컬 추천 상품, 여행자 전용 패키지','1인 평균 10,000원 - 30,000원','인근 공영주차장 이용 가능','https://map.naver.com','https://www.instagram.com');
